using UnityEngine;
using Climbing;
using System.Reflection;

public class DebugPlayerStatus
{
    public static string Run()
    {
        ClimbController cc = Object.FindObjectOfType<ClimbController>();
        if (cc == null) return "No player found in scene.";

        GameObject pm = cc.gameObject;
        ThirdPersonController tpc = pm.GetComponent<ThirdPersonController>();
        DetectionCharacterController dcc = pm.GetComponent<DetectionCharacterController>();
        Animator anim = pm.GetComponent<Animator>();

        string report = $"--- Player: {pm.name} ---\n";
        report += $"Position: {pm.transform.position}\n";

        if (tpc != null) {
            report += $"TPC: isGrounded={tpc.isGrounded}, onAir={tpc.onAir}, isJumping={tpc.isJumping}, allowMovement={tpc.allowMovement}\n";
        }

        if (dcc != null) {
            bool grounded = dcc.IsGrounded(0.8f); // testing with default stepHeight
            report += $"DCC Ground Check (manual): {grounded}\n";
        }

        if (anim != null) {
            AnimatorStateInfo state = anim.GetCurrentAnimatorStateInfo(0);
            report += $"Animator State: {state.fullPathHash} (IsFalling={state.IsName("Fall")})\n";
            report += $"Animator Parameters: speed={anim.GetFloat("velocity")}, horizontal={anim.GetFloat("horizontal")}, vertical={anim.GetFloat("vertical")}\n";
        }

        RaycastHit hit;
        if (Physics.Raycast(pm.transform.position + new Vector3(0, 0.3f, 0), Vector3.down, out hit, 10f)) {
            report += $"Physics Raycast: Found {hit.collider.name} at {hit.distance} units (Point: {hit.point})\n";
        } else {
            report += "Physics Raycast: Found nothing for 10 units below (0.3 offset).\n";
        }

        return report;
    }
}
